const COMPLETION_STEPS = [
  { id:'name',       label:'Display name',        check: p => !!p.name?.trim() },
  { id:'dob',        label:'Birthday',             check: p => !!p.dob },
  { id:'bio',        label:'Bio',                  check: p => !!p.bio?.trim() },
  { id:'avatar',     label:'Profile photo/avatar', check: p => !!(p.photoUrl || (p.emoji && p.emoji !== '🎂')) },
  { id:'background', label:'Page background',      check: p => !!(p.background && p.background.id !== 'default') },
  { id:'goal',       label:'Squad goal',           check: p => !!p.goal },
  { id:'wishlist',   label:'Wishlist item',        check: p => (DB.wishlists[p.id]||[]).length > 0 },
  { id:'wall',       label:'Birthday wall post',   check: p => (DB.walls[p.id]||[]).some(w=>w.user===p.name) },
  { id:'follower',   label:'First follower',       check: p => FollowStore.getFollowers(p.id).length > 0 },
];

const getCompletionScore = (profile) => {
  if(!profile) return {score:0, pct:0, missing:[], done:[]};
  const done    = COMPLETION_STEPS.filter(s => s.check(profile));
  const missing = COMPLETION_STEPS.filter(s => !s.check(profile));
  const pct     = Math.round((done.length / COMPLETION_STEPS.length) * 100);
  return { score: done.length, total: COMPLETION_STEPS.length, pct, done, missing };
};
