const seedDemoPoints = (uid, profile) => {
  const mk = PointsStore.getMonthKey();
  const existing = PointsStore.getData(uid);
  if(existing[mk]) return;
  const actions = ['gift_10','gift_25','wall_post','wishlist','ai_concierge','refer_signup'];
  actions.forEach(a => { for(let i=0;i<2;i++) PointsStore.earn(uid,a); });
  try {
    const target = DEMO_LIFETIME_POINTS[uid] ?? 220;
    const cur = PointsStore.getLifetime(uid);
    if(cur < target) localStorage.setItem(PointsStore._lifeKey(uid), String(target));
  } catch {}
};
const AnnouncementStore = {
  post(userId, text) {
    if(!DB.announcements[userId]) DB.announcements[userId]=[];
    const ann = {id:Date.now(), text, ts:Date.now(), reactions:{}, reactedBy:{}};
    DB.announcements[userId].unshift(ann);
    DB.announcements[userId]=DB.announcements[userId].slice(0,10);
    return ann;
  },
  get(userId) { return (DB.announcements[userId]||[])[0]||null; },
  react(userId, annId, emoji, reactorId) {
    const ann=(DB.announcements[userId]||[]).find(a=>a.id===annId); if(!ann) return;
    if(!ann.reactions[emoji]) ann.reactions[emoji]=0;
    if(!ann.reactedBy[reactorId]) ann.reactedBy[reactorId]={};
    if(ann.reactedBy[reactorId][emoji]){ann.reactions[emoji]--;delete ann.reactedBy[reactorId][emoji];}
    else{ann.reactions[emoji]++;ann.reactedBy[reactorId][emoji]=true;}
  },
  delete(userId, annId) { if(DB.announcements[userId]) DB.announcements[userId]=DB.announcements[userId].filter(a=>a.id!==annId); },
};
