// ── Daily Check-in / Streak System ───────────────────────────────────────────
const CheckInStore = {
  _key: (uid) => `checkin_${uid}`,
  getData(uid) {
    try {
      const raw = localStorage.getItem(this._key(uid));
      return raw ? JSON.parse(raw) : { lastDate: null, streak: 0, totalCheckins: 0, lastPoints: 0 };
    } catch { return { lastDate: null, streak: 0, totalCheckins: 0, lastPoints: 0 }; }
  },
  _save(uid, data) {
    try { localStorage.setItem(this._key(uid), JSON.stringify(data)); } catch {}
  },
  // Returns { alreadyCheckedIn, pointsEarned, newStreak, isStreakBonus }
  checkIn(uid) {
    const today = new Date().toDateString();
    const data = this.getData(uid);
    if (data.lastDate === today) return { alreadyCheckedIn: true, pointsEarned: 0, newStreak: data.streak };
    const yesterday = new Date(Date.now() - 86400000).toDateString();
    const newStreak = data.lastDate === yesterday ? data.streak + 1 : 1;
    // Points: base 5, +5 every 7 days streak, +20 bonus on 7-day milestone
    const base = 5;
    const streakBonus = newStreak % 7 === 0 ? 20 : 0;
    const promoMult = DB.pointsConfig?.promo_active ? (DB.pointsConfig?.promo_multiplier ?? 1) : 1;
    const pointsEarned = (base + streakBonus) * promoMult;
    const isStreakBonus = streakBonus > 0;
    const updated = { lastDate: today, streak: newStreak, totalCheckins: (data.totalCheckins||0)+1, lastPoints: pointsEarned };
    this._save(uid, updated);
    // Award points to profile
    if (DB.users[uid]) {
      DB.users[uid].points = (DB.users[uid].points||0) + pointsEarned;
    }
    return { alreadyCheckedIn: false, pointsEarned, newStreak, isStreakBonus };
  },
  hasCheckedInToday(uid) {
    const today = new Date().toDateString();
    return this.getData(uid).lastDate === today;
  },
};

// ── Saved Gift Ideas Store — product interest graph for AI personalization ──
const SavedItemsStore = {
  _key: 'bm_saved_items',
  _load(userId){
    try {
      const all = JSON.parse(localStorage.getItem(SavedItemsStore._key) || '{}');
      return all[userId] || [];
    } catch { return []; }
  },
  _save(userId, items){
    try {
      const all = JSON.parse(localStorage.getItem(SavedItemsStore._key) || '{}');
      all[userId] = items;
      localStorage.setItem(SavedItemsStore._key, JSON.stringify(all));
    } catch {}
  },
  getAll(userId){ return SavedItemsStore._load(userId); },
  isSaved(userId, itemId){ return SavedItemsStore._load(userId).some(i => i.id === itemId); },
  toggle(userId, item){
    const items = SavedItemsStore._load(userId);
    const idx = items.findIndex(i => i.id === item.id);
    if(idx >= 0){
      items.splice(idx, 1);
      SavedItemsStore._save(userId, items);
      return false; // removed
    } else {
      items.unshift({...item, savedAt: Date.now()});
      SavedItemsStore._save(userId, items.slice(0, 200)); // cap at 200
      return true; // added
    }
  },
  // Build interest profile for AI personalization
  getInterestProfile(userId){
    const items = SavedItemsStore._load(userId);
    if(!items.length) return null;
    const categories = {};
    const pricePoints = [];
    const stores = {};
    items.forEach(item => {
      if(item.category) categories[item.category] = (categories[item.category]||0) + 1;
      if(item.price) pricePoints.push(parseFloat(item.price.replace(/[^0-9.]/g,''))||0);
      if(item.store) stores[item.store] = (stores[item.store]||0) + 1;
    });
    const topCategories = Object.entries(categories).sort((a,b)=>b[1]-a[1]).slice(0,3).map(e=>e[0]);
    const avgPrice = pricePoints.length ? Math.round(pricePoints.reduce((a,b)=>a+b,0)/pricePoints.length) : null;
    const topStores = Object.entries(stores).sort((a,b)=>b[1]-a[1]).slice(0,3).map(e=>e[0]);
    const recentTitles = items.slice(0,10).map(i=>i.title);
    return {topCategories, avgPrice, topStores, recentTitles, totalSaved: items.length};
  },
};
const AnalyticsStore = {
  recordView(profileId, source='direct'){
    if(!DB.analytics[profileId]) DB.analytics[profileId]={views:[],contributors:new Set()};
    DB.analytics[profileId].views.push({ts:Date.now(), source, day:new Date().toDateString()});
  },
  recordContribution(profileId, amount){
    if(!DB.analytics[profileId]) DB.analytics[profileId]={views:[],contributors:new Set()};
    DB.analytics[profileId].contributors.add(Date.now()+Math.random());
  },
  getStats(profileId){
    const d = DB.analytics[profileId]||{views:[],contributors:new Set()};
    const now = Date.now();
    const day  = d.views.filter(v=>now-v.ts < 864e5).length;
    const week = d.views.filter(v=>now-v.ts < 7*864e5).length;
    const total = d.views.length;
    const sources = {};
    d.views.forEach(v=>{ sources[v.source]=(sources[v.source]||0)+1; });
    const topSource = Object.entries(sources).sort((a,b)=>b[1]-a[1])[0]?.[0]||'direct';
    const convRate = total>0 ? Math.round((d.contributors.size/total)*100) : 0;
    return {day, week, total, topSource, convRate, contributors: d.contributors.size};
  }
};
