const FollowStore = {
  follow(followerId, targetId){
    if(!DB.follows[followerId]) DB.follows[followerId]=new Set();
    DB.follows[followerId].add(targetId);
  },
  unfollow(followerId, targetId){
    DB.follows[followerId]?.delete(targetId);
    // also remove any pending request
    if(DB.followRequests[targetId]){
      DB.followRequests[targetId]=DB.followRequests[targetId].filter(r=>r.fromId!==followerId);
    }
  },
  isFollowing(followerId, targetId){
    return DB.follows[followerId]?.has(targetId)||false;
  },
  hasPendingRequest(fromId, targetId){
    return (DB.followRequests[targetId]||[]).some(r=>r.fromId===fromId);
  },
  requestFollow(fromId, fromName, targetId){
    if(!DB.followRequests[targetId]) DB.followRequests[targetId]=[];
    if(!this.hasPendingRequest(fromId, targetId)){
      DB.followRequests[targetId].push({fromId, fromName, ts:Date.now()});
    }
  },
  approveRequest(fromId, targetId){
    if(!DB.follows[fromId]) DB.follows[fromId]=new Set();
    DB.follows[fromId].add(targetId);
    if(DB.followRequests[targetId]){
      DB.followRequests[targetId]=DB.followRequests[targetId].filter(r=>r.fromId!==fromId);
    }
  },
  declineRequest(fromId, targetId){
    if(DB.followRequests[targetId]){
      DB.followRequests[targetId]=DB.followRequests[targetId].filter(r=>r.fromId!==fromId);
    }
  },
  getPendingRequests(targetId){
    return DB.followRequests[targetId]||[];
  },
  getFollowing(followerId){
    return [...(DB.follows[followerId]||new Set())];
  },
  getFollowerCount(targetId){
    return Object.values(DB.follows).filter(s=>s.has(targetId)).length;
  },
  getFollowingCount(userId){
    return (DB.follows[userId]?.size)||0;
  },
  getFollowers(targetId){
    return Object.keys(DB.follows).filter(uid=>DB.follows[uid]?.has(targetId));
  },
};
