// ── LoginAttemptStore — tracks failed login attempts for lockout ──────────────
const LoginAttemptStore = {
  MAX_ATTEMPTS: 5,
  LOCKOUT_MS: 30 * 60 * 1000, // 30 minutes initial

  _key: (id) => `bm_login_${id}`,

  getRecord(identifier) {
    try {
      const stored = localStorage.getItem(this._key(identifier));
      return stored ? JSON.parse(stored) : {count:0, lockedUntil:null, lastAttempt:null};
    } catch { return {count:0, lockedUntil:null, lastAttempt:null}; }
  },

  saveRecord(identifier, record) {
    try { localStorage.setItem(this._key(identifier), JSON.stringify(record)); } catch {}
  },

  isLocked(identifier) {
    const rec = this.getRecord(identifier);
    if(!rec.lockedUntil) return false;
    if(Date.now() < rec.lockedUntil) return {locked:true, remaining: Math.ceil((rec.lockedUntil - Date.now())/60000)};
    // Auto-expire
    rec.lockedUntil = null;
    this.saveRecord(identifier, rec);
    return false;
  },

  recordFailure(identifier) {
    const rec = this.getRecord(identifier);
    rec.count = (rec.count||0) + 1;
    rec.lastAttempt = Date.now();
    if(rec.count >= this.MAX_ATTEMPTS) {
      // Exponential backoff: 30min, 1hr, 2hr, permanent
      const multiplier = Math.min(Math.pow(2, Math.floor(rec.count/5)-1), 8);
      rec.lockedUntil = Date.now() + (this.LOCKOUT_MS * multiplier);
    }
    this.saveRecord(identifier, rec);
    return rec.count;
  },

  recordSuccess(identifier) {
    this.saveRecord(identifier, {count:0, lockedUntil:null, lastAttempt:null});
  },

  adminUnlock(identifier) {
    this.saveRecord(identifier, {count:0, lockedUntil:null, lastAttempt:null});
  },

  getAttemptCount(identifier) {
    return this.getRecord(identifier).count || 0;
  },

  setForcePwdChange(userId) {
    if(!DB.forcePwdChange) DB.forcePwdChange = {};
    DB.forcePwdChange[userId] = true;
  },

  clearForcePwdChange(userId) {
    if(DB.forcePwdChange) delete DB.forcePwdChange[userId];
  },

  requiresPwdChange(userId) {
    return !!(DB.forcePwdChange||{})[userId];
  },
};

