const SupportTicketStore = {
  create(data) {
    if(!DB.supportTickets) DB.supportTickets = [];
    const ticket = {
      id: `ticket_${Date.now()}`,
      email: data.email||'',
      username: data.username||'',
      issue: data.issue||'Account access issue',
      detail: data.detail||'',
      ts: Date.now(),
      status: 'open',
      tempPass: null,
    };
    DB.supportTickets.unshift(ticket);
    return ticket;
  },
  getAll() { return DB.supportTickets||[]; },
  getOpen() { return (DB.supportTickets||[]).filter(t=>t.status==='open'); },
  resolve(id, tempPass=null) {
    const t = (DB.supportTickets||[]).find(t=>t.id===id);
    if(t) { t.status='resolved'; t.resolvedAt=Date.now(); if(tempPass) t.tempPass=tempPass; }
  },
  generateTempPass() {
    const chars = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789';
    return Array.from({length:8}, ()=>chars[Math.floor(Math.random()*chars.length)]).join('');
  },
};

// ── ContentFlagStore ──────────────────────────────────────────────────────────
const ContentFlagStore = {
  flag(postId, reason='reported', userId=null) {
    if(!DB.contentFlags) DB.contentFlags = {};
    if(DB.contentFlags[postId]) {
      const f = DB.contentFlags[postId];
      f.reportCount = (f.reportCount||1) + 1;
      // Track unique reporters for brigading detection
      if(userId && !(f.reporters||[]).includes(userId)) {
        f.reporters = [...(f.reporters||[]), userId];
      }
    } else {
      DB.contentFlags[postId] = {
        postId, reason, flaggedAt:Date.now(), status:'pending',
        reportCount:1, flaggedBy:userId,
        reporters: userId ? [userId] : [],
        autoFlagged: reason.startsWith('keyword:'),
      };
    }
    // Brigading detection: 5+ reports within 2hrs from accounts sharing same followers → mark suspected
    this._checkBrigading(postId);
  },
  _checkBrigading(postId) {
    const f = DB.contentFlags?.[postId];
    if(!f || f.reporters?.length < 3) return;
    const twoHrsAgo = Date.now() - 7200000;
    if(f.flaggedAt > twoHrsAgo && f.reporters?.length >= 3) {
      // Check if reporters have overlapping social graphs (shared followees)
      const reporterAccounts = (f.reporters||[]).map(id => DB.users[id]).filter(Boolean);
      const newAccounts = reporterAccounts.filter(u => {
        const age = Date.now() - (u.createdAt || Date.now());
        return age < 7 * 86400000; // < 7 days old
      });
      if(newAccounts.length >= 2 || f.reporters?.length >= 5) {
        f.suspectedBrigading = true;
      }
    }
  },
  getFlagged() { return Object.values(DB.contentFlags||{}).filter(f=>f.status==='pending'); },
  getAll() { return Object.values(DB.contentFlags||{}); },
  getDisputes() { return Object.values(DB.contentFlags||{}).filter(f=>f.disputed && f.disputeStatus==='pending_admin'); },
  dismiss(postId) { if(DB.contentFlags?.[postId]) DB.contentFlags[postId].status='dismissed'; },
  restore(postId) {
    if(DB.contentFlags?.[postId]) {
      DB.contentFlags[postId].status = 'restored';
      DB.contentFlags[postId].reportCount = 0;
    }
    // Un-hide the post from walls
    Object.values(DB.walls||{}).forEach(posts => {
      const p = posts.find(p=>p.id==postId);
      if(p) { p.hidden = false; p.restoredAt = Date.now(); }
    });
  },
  remove(postId) {
    if(DB.contentFlags?.[postId]) DB.contentFlags[postId].status='removed';
    Object.values(DB.walls||{}).forEach(posts => {
      const idx = posts.findIndex(p=>p.id==postId);
      if(idx>-1) posts.splice(idx,1);
    });
  },
  hide(postId) {
    if(DB.contentFlags?.[postId]) DB.contentFlags[postId].status='hidden';
    Object.values(DB.walls||{}).forEach(posts => {
      const p = posts.find(p=>p.id==postId);
      if(p) p.hidden = true;
    });
  },
  // Dispute: user challenges a flag on their post
  dispute(postId, userId, message='') {
    if(!DB.contentFlags) DB.contentFlags = {};
    if(!DB.contentFlags[postId]) return;
    const f = DB.contentFlags[postId];
    // Check dispute limit (max 2 successful disputes before requiring admin review)
    const userDisputes = DB.disputeHistory?.[userId] || [];
    const successfulDisputes = userDisputes.filter(d=>d.outcome==='restored').length;
    f.disputed = true;
    f.disputedAt = Date.now();
    f.disputedBy = userId;
    f.disputeMessage = message;
    f.disputeStatus = successfulDisputes >= 2 ? 'pending_admin' : 'ai_review';
    f.intentConfirmed = DB.walls && Object.values(DB.walls).flat().find(p=>p.id==postId)?.userConfirmedIntent || false;
    if(!DB.disputes) DB.disputes = {};
    DB.disputes[postId] = {
      postId, userId, message, ts: Date.now(),
      flagReason: f.reason, reportCount: f.reportCount,
      reporters: f.reporters || [],
      intentConfirmed: f.intentConfirmed,
      status: f.disputeStatus,
      aiAssessment: null,
    };
  },
  resolveDispute(postId, outcome, adminNote='') {
    const f = DB.contentFlags?.[postId];
    const d = DB.disputes?.[postId];
    if(!f || !d) return;
    d.outcome = outcome;
    d.adminNote = adminNote;
    d.resolvedAt = Date.now();
    f.disputeStatus = outcome;
    if(outcome === 'restored') this.restore(postId);
    else if(outcome === 'upheld') this.hide(postId);
    // Track in user dispute history
    if(!DB.disputeHistory) DB.disputeHistory = {};
    if(!DB.disputeHistory[d.userId]) DB.disputeHistory[d.userId] = [];
    DB.disputeHistory[d.userId].push({postId, outcome, ts: Date.now()});
  },
  // Check post text against keyword blocklist with severity
  checkKeywords(text) {
    if(!text) return false;
    const lower = text.toLowerCase();
    const keywords = DB.keywordBlocklist || [];
    // Support both old string format and new {word, severity, mode} format
    for(const kw of keywords) {
      const word = typeof kw === 'string' ? kw : kw.word;
      const severity = typeof kw === 'string' ? 'warn' : (kw.severity || 'warn');
      if(lower.includes(word.toLowerCase())) return {word, severity};
    }
    return false;
  },
  autoCheck(postId, text, userId) {
    const hit = this.checkKeywords(text);
    if(hit && hit.severity !== 'warn') this.flag(postId, `keyword:${hit.word}`, userId);
    return hit || false;
  },
  // Reporter credibility: reporters whose flags get dismissed frequently get lower weight
  getReporterWeight(userId) {
    const history = DB.reporterHistory?.[userId] || {upheld:0, dismissed:0};
    const total = history.upheld + history.dismissed;
    if(total < 3) return 1.0; // not enough history
    return Math.max(0.1, history.upheld / total);
  },
};


// ── DisputeNotifHelper — push enriched flag notifications to post authors ──────
const DisputeNotifHelper = {
  pushFlaggedNotif(postId, postText, flagReason, postAuthorId) {
    if(!postAuthorId) return;
    const snippet = postText?.length > 60 ? postText.slice(0,57)+'...' : postText;
    NotifStore.push(postAuthorId, {
      icon: '🚩',
      text: `Your post was flagged for review: "${snippet}"`,
      sub: `Reason: ${flagReason || 'Community report'} · Tap to dispute if this was a mistake`,
      color: 'var(--gold)',
      route: 'dispute',
      postId,
      flagReason,
      postText,
      isDisputeNotif: true,
    });
  },
  pushDisputeResolved(userId, outcome, postText) {
    const snippet = postText?.length > 50 ? postText.slice(0,47)+'...' : postText;
    NotifStore.push(userId, {
      icon: outcome === 'restored' ? '✅' : '⚠️',
      text: outcome === 'restored'
        ? `Your dispute was approved — your post has been restored`
        : `Your dispute was reviewed — the flag on your post was upheld`,
      sub: `Post: "${snippet}"`,
      color: outcome === 'restored' ? 'var(--mint)' : 'var(--coral)',
      route: 'wall',
    });
  },
};

// ── SessionStore — manages concurrent device sessions (max 3) ────────────────
const SessionStore = {
  MAX_SESSIONS: 3,

  getSessions(userId) {
    return DB.sessions?.[userId] || [];
  },

  addSession(userId, sessionInfo) {
    if(!DB.sessions) DB.sessions = {};
    const sessions = this.getSessions(userId);
    const newSession = {
      sessionId: 'sess_' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
      device: sessionInfo.device || this._detectDevice(),
      browser: sessionInfo.browser || navigator.userAgent.split(' ').pop(),
      ip: sessionInfo.ip || 'Unknown',
      city: sessionInfo.city || 'Unknown',
      lastActive: Date.now(),
      createdAt: Date.now(),
      current: true,
    };
    // Mark all existing as non-current
    sessions.forEach(s => s.current = false);
    sessions.push(newSession);
    DB.sessions[userId] = sessions;
    return { session: newSession, overLimit: sessions.length > this.MAX_SESSIONS };
  },

  _detectDevice() {
    const ua = navigator.userAgent;
    if(/iPad/.test(ua)) return 'iPad';
    if(/iPhone|Android.*Mobile/.test(ua)) return 'Mobile';
    if(/Android/.test(ua)) return 'Tablet';
    return 'Desktop';
  },

  removeSession(userId, sessionId) {
    if(!DB.sessions?.[userId]) return;
    DB.sessions[userId] = DB.sessions[userId].filter(s => s.sessionId !== sessionId);
  },

  removeAllOtherSessions(userId, currentSessionId) {
    if(!DB.sessions?.[userId]) return;
    DB.sessions[userId] = DB.sessions[userId].filter(s => s.sessionId === currentSessionId);
  },

  updateActivity(userId, sessionId) {
    const sessions = this.getSessions(userId);
    const s = sessions.find(s => s.sessionId === sessionId);
    if(s) s.lastActive = Date.now();
  },

  isOverLimit(userId) {
    return this.getSessions(userId).length > this.MAX_SESSIONS;
  },
};

// ── VelocityStore — dynamic incoming gift limits based on follower count ───────
const VelocityStore = {
  // Get the daily incoming contribution limit based on follower count
  getLimit(userId) {
    try {
      const user = DB.users?.[userId];
      if(!user) return 50;
      if(user.is_verified || user.is_vip) return Infinity; // verified/VIP unlimited
      const followers = (DB.followers?.[userId]?.length) || 0;
      if(followers >= 10001) return 10000;
      if(followers >= 1001)  return 1000;
      if(followers >= 101)   return 500;
      if(followers >= 11)    return 200;
      return 50; // base limit for new users
    } catch(e) { return 50; }
  },

  // Check if a contribution would exceed the daily limit
  checkContribution(recipientId, amount) {
    const limit = this.getLimit(recipientId);
    if(limit === Infinity) return { allowed: true };
    const today = new Date().toDateString();
    if(!DB.velocityLimits) DB.velocityLimits = {};
    const record = DB.velocityLimits[recipientId];
    const isToday = record && new Date(record.windowStart).toDateString() === today;
    const currentTotal = isToday ? (record.totalReceived || 0) : 0;
    if(currentTotal + amount > limit) {
      return { allowed: false, limit, current: currentTotal, remaining: Math.max(0, limit - currentTotal) };
    }
    return { allowed: true, limit, current: currentTotal };
  },

  // Record a completed contribution
  recordContribution(recipientId, amount) {
    if(!DB.velocityLimits) DB.velocityLimits = {};
    const today = new Date().toDateString();
    const record = DB.velocityLimits[recipientId];
    const isToday = record && new Date(record.windowStart).toDateString() === today;
    if(isToday) {
      DB.velocityLimits[recipientId].totalReceived = (record.totalReceived || 0) + amount;
    } else {
      DB.velocityLimits[recipientId] = { windowStart: Date.now(), totalReceived: amount };
    }
  },

  // Get follower-based limit tier label
  getLimitLabel(userId) {
    const limit = this.getLimit(userId);
    if(limit === Infinity) return 'Unlimited (Verified)';
    return `$${limit.toLocaleString()}/day`;
  },
};

// ── HoneypotStore — detect bot submissions ────────────────────────────────────
const HoneypotStore = {
  // Returns true if honeypot was filled (bot detected)
  check(honeypotValue) {
    return honeypotValue && honeypotValue.length > 0;
  },
  // Generate a plausible-looking field name that bots will fill
  fieldName: 'website_url_confirm',
};

// ── URLValidator — validate business URLs for phishing ────────────────────────
const URLValidator = {
  // Allowlisted domains that are always safe
  SAFE_DOMAINS: ['amazon.com','etsy.com','shopify.com','stripe.com','paypal.com',
    'venmo.com','square.com','giftcards.com','target.com','walmart.com','bestbuy.com',
    'sephora.com','ulta.com','airbnb.com','masterclass.com','goldbelly.com','google.com'],

  validate(url) {
    if(!url || !url.trim()) return { valid: true }; // empty is ok
    try {
      const u = new URL(url.startsWith('http') ? url : 'https://'+url);
      const hostname = u.hostname.toLowerCase().replace('www.','');
      // Block IP addresses
      if(/^\d+\.\d+\.\d+\.\d+$/.test(hostname)) return { valid: false, reason: 'IP addresses not allowed' };
      // Block known URL shorteners
      const shorteners = ['bit.ly','tinyurl.com','t.co','goo.gl','ow.ly','short.io'];
      if(shorteners.some(s => hostname.includes(s))) return { valid: false, reason: 'URL shorteners not allowed' };
      // Block non-HTTPS
      if(u.protocol !== 'https:') return { valid: false, reason: 'Only HTTPS URLs allowed' };
      return { valid: true, hostname };
    } catch {
      return { valid: false, reason: 'Invalid URL format' };
    }
  },
};



// ── SecurityNudgeStore — stake-based enforcement of security question ────────
const SECURITY_NUDGE_THRESHOLDS = {
  minBalance:    5,    // $ — configurable via admin
  minPoints:     100,
  minDaysOnPlatform: 7,
  maxSoftDismisses: 2, // after this, nudge becomes hard (no dismiss)
};

const SecurityNudgeStore = {
  // Check if user needs security question nudge
  needsNudge(userId) {
    if(!userId) return false;
    if(SecurityQuestionStore.hasQuestion(userId)) return false;
    const user = DB.users?.[userId];
    if(!user || user.isDemo) return false;
    return true;
  },

  // Determine nudge intensity based on what user has at stake
  getNudgeLevel(userId) {
    if(!this.needsNudge(userId)) return 'none';
    const user = DB.users?.[userId];
    if(!user) return 'none';

    const balance = user.raised || 0;
    const points = PointsStore.getLifetime(userId);
    const daysSinceJoin = user.createdAt
      ? Math.floor((Date.now() - user.createdAt) / (1000 * 60 * 60 * 24))
      : 0;
    const hasReceivedGift = (DB.giftHistory || []).some(g => g.recipientId === userId);

    // Hard enforcement — no dismiss allowed
    if(
      hasReceivedGift ||
      balance >= SECURITY_NUDGE_THRESHOLDS.minBalance ||
      points >= SECURITY_NUDGE_THRESHOLDS.minPoints ||
      daysSinceJoin >= SECURITY_NUDGE_THRESHOLDS.minDaysOnPlatform
    ) {
      // Check if they've already used their soft dismisses
      const record = DB.securityNudge?.[userId] || {};
      if(record.dismissCount >= SECURITY_NUDGE_THRESHOLDS.maxSoftDismisses) {
        return 'hard';
      }
      return 'hard'; // once thresholds crossed, always hard
    }

    // Soft nudge — new account, nothing at stake yet
    return 'soft';
  },

  // Get the reason string explaining why enforcement is happening
  getStakeReason(userId) {
    const user = DB.users?.[userId];
    if(!user) return null;
    const balance = user.raised || 0;
    const points = PointsStore.getLifetime(userId);
    const hasReceivedGift = (DB.giftHistory || []).some(g => g.recipientId === userId);
    const daysSinceJoin = user.createdAt
      ? Math.floor((Date.now() - user.createdAt) / (1000 * 60 * 60 * 24))
      : 0;

    if(hasReceivedGift && balance >= SECURITY_NUDGE_THRESHOLDS.minBalance)
      return { icon: '🎁', text: "You've received birthday gifts — protect access to your balance." };
    if(hasReceivedGift)
      return { icon: '🎁', text: "You've received your first gift. Secure your account to protect it." };
    if(balance >= SECURITY_NUDGE_THRESHOLDS.minBalance)
      return { icon: '💰', text: `You have $${balance.toFixed(2)} in your account — make sure you can always access it.` };
    if(points >= SECURITY_NUDGE_THRESHOLDS.minPoints)
      return { icon: '🏆', text: `You've earned ${points} points — secure your account to protect your progress.` };
    if(daysSinceJoin >= SECURITY_NUDGE_THRESHOLDS.minDaysOnPlatform)
      return { icon: '📅', text: "You've been on BirthdayMe for a week — time to secure your account." };
    return { icon: '🔐', text: "Add a security question to protect your account." };
  },

  recordSoftDismiss(userId) {
    if(!DB.securityNudge) DB.securityNudge = {};
    if(!DB.securityNudge[userId]) DB.securityNudge[userId] = {dismissCount:0};
    DB.securityNudge[userId].dismissCount++;
    DB.securityNudge[userId].dismissedAt = Date.now();
  },

  getSoftDismissCount(userId) {
    return DB.securityNudge?.[userId]?.dismissCount || 0;
  },

  // Mark as completed (called when question is set)
  markComplete(userId) {
    if(!DB.securityNudge) DB.securityNudge = {};
    DB.securityNudge[userId] = { ...DB.securityNudge[userId], completed: true, completedAt: Date.now() };
  },
};

// ── SecurityQuestionStore — account recovery via secret question ──────────────
const SECURITY_QUESTIONS = [
  {id:'first_pet',            label:"What was the name of your first pet?"},
  {id:'childhood_street',     label:"What street did you grow up on?"},
  {id:'elementary_school',    label:"What was the name of your elementary school?"},
  {id:'maternal_grandmother', label:"What is your maternal grandmother's maiden name?"},
  {id:'first_car',            label:"What was the make of your first car?"},
  {id:'childhood_nickname',   label:"What was your childhood nickname?"},
];

const SecurityQuestionStore = {
  // Normalize answer before storing/comparing (lowercase + trim)
  normalize(answer) { return (answer||'').toLowerCase().trim(); },

  // Simple hash for Phase 1 (Phase 2: bcrypt via Edge Function)
  hash(answer) {
    const n = this.normalize(answer);
    let h = 0;
    for(let i = 0; i < n.length; i++) { h = ((h << 5) - h) + n.charCodeAt(i); h |= 0; }
    return 'sq_' + Math.abs(h).toString(36) + '_' + n.length;
  },

  set(userId, questionId, answer) {
    if(!DB.securityQuestions) DB.securityQuestions = {};
    DB.securityQuestions[userId] = {
      questionId,
      answerHash: this.hash(answer),
      setAt: Date.now(),
    };
  },

  verify(userId, answer) {
    const record = DB.securityQuestions?.[userId];
    if(!record) return false;
    return record.answerHash === this.hash(answer);
  },

  getQuestion(userId) {
    const record = DB.securityQuestions?.[userId];
    if(!record) return null;
    return SECURITY_QUESTIONS.find(q => q.id === record.questionId) || null;
  },

  hasQuestion(userId) {
    return !!(DB.securityQuestions?.[userId]);
  },

  getQuestions() { return SECURITY_QUESTIONS; },
};

// ── RecoveryAttemptStore — 3-attempt lockout for security question recovery ───
const RecoveryAttemptStore = {
  MAX_ATTEMPTS: 3,
  LOCKOUT_MS: 30 * 60 * 1000, // 30 minutes

  getRecord(userId) {
    return DB.recoveryAttempts?.[userId] || null;
  },

  isLocked(userId) {
    const r = this.getRecord(userId);
    if(!r || !r.lockedUntil) return false;
    return Date.now() < r.lockedUntil;
  },

  getRemainingLockMs(userId) {
    const r = this.getRecord(userId);
    if(!r?.lockedUntil) return 0;
    return Math.max(0, r.lockedUntil - Date.now());
  },

  recordFailure(userId) {
    if(!DB.recoveryAttempts) DB.recoveryAttempts = {};
    const r = DB.recoveryAttempts[userId] || {count:0};
    r.count = (r.count || 0) + 1;
    r.lastAttempt = Date.now();
    if(r.count >= this.MAX_ATTEMPTS) {
      r.lockedUntil = Date.now() + this.LOCKOUT_MS;
    }
    DB.recoveryAttempts[userId] = r;
    return r.count;
  },

  reset(userId) {
    if(DB.recoveryAttempts?.[userId]) {
      delete DB.recoveryAttempts[userId];
    }
  },
};

// ── SupportHistoryStore — structured AI chat memory per user ─────────────────
const SupportHistoryStore = {
  MAX_ENTRIES: 5,

  getHistory(userId) {
    return DB.supportHistory?.[userId]?.summary || [];
  },

  getSummaryForPrompt(userId) {
    const history = this.getHistory(userId);
    if(!history.length) return '';
    const lines = history.map(function(e, i) {
      return (i+1) + '. ' + e.issue + ' (' + new Date(e.ts).toLocaleDateString() + ') - ' + e.resolution;
    });
    const entries = lines.join('\n');
    const header = '\n\nThis user recent support history (use for context only, do not volunteer unprompted):\n';
    return header + entries;
  },

  addEntry(userId, issue, resolution) {
    if(!DB.supportHistory) DB.supportHistory = {};
    if(!DB.supportHistory[userId]) DB.supportHistory[userId] = {summary:[]};
    const summary = DB.supportHistory[userId].summary;
    summary.unshift({issue, resolution, ts: Date.now()});
    if(summary.length > this.MAX_ENTRIES) summary.pop();
    DB.supportHistory[userId].lastContactAt = Date.now();
  },

  clearHistory(userId) {
    if(DB.supportHistory?.[userId]) delete DB.supportHistory[userId];
  },
};

// ── CaseIDStore — generate BM-YYYY-XXXXXX case IDs ───────────────────────────
const CaseIDStore = {
  _seq: 1000,
  generate() {
    const year = new Date().getFullYear();
    const num = String(++this._seq).padStart(6, '0');
    return `BM-${year}-${num}`;
  },
};

const BlockStore = {
  block(blockerId, targetId){
    if(!DB.blocks[blockerId]) DB.blocks[blockerId]=new Set();
    DB.blocks[blockerId].add(targetId);
    FollowStore.unfollow(blockerId, targetId);
    FollowStore.unfollow(targetId, blockerId);
  },
  unblock(blockerId, targetId){
    DB.blocks[blockerId]?.delete(targetId);
  },
  isBlocked(blockerId, targetId){
    return DB.blocks[blockerId]?.has(targetId)||false;
  },
  getBlockedList(userId){
    return [...(DB.blocks[userId]||new Set())];
  },
  anyBlock(userA, userB){
    return BlockStore.isBlocked(userA,userB)||BlockStore.isBlocked(userB,userA);
  },
};
const FOLLOWER_BADGE_TIERS = [
  {count:1,    id:"first_follower"},
  {count:10,   id:"circle_10"},
  {count:50,   id:"party_50"},
  {count:100,  id:"hundred_club"},
  {count:500,  id:"bday_royalty"},
  {count:1000, id:"legend_1k"},
];
const checkFollowerBadges = (targetId) => {
  const user = DB.users[targetId];
  if(!user) return;
  const count = FollowStore.getFollowerCount(targetId);
  if(!user.badges) user.badges=[];
  FOLLOWER_BADGE_TIERS.forEach(tier=>{
    if(count>=tier.count && !user.badges.includes(tier.id)){
      user.badges.push(tier.id);
      const b = BADGES.find(x=>x.id===tier.id);
      if(b) NotifStore.push(targetId,{
        icon: b.icon,
        text: `You earned the "${b.label}" badge — ${b.desc}! 🎉`,
        color:"var(--gold)", route:"badges"
      });
    }
  });
};
const fmtCount = n => n>=1000 ? (n/1000).toFixed(1).replace(/\.0$/,'')+"k" : String(n);
const NotifStore = {
  _listeners: [],
  subscribe(fn){ this._listeners.push(fn); return ()=>{ this._listeners=this._listeners.filter(l=>l!==fn); }; },
  emit(notif){ this._listeners.forEach(fn=>fn(notif)); },
  push(userId, notif){
    if(!DB.notifications[userId]) DB.notifications[userId]=[];
    const entry={...notif, id:Date.now()+Math.random(), ts:new Date(), read:false};
    DB.notifications[userId].unshift(entry);
    this.emit(entry);
    return entry;
  },
  getAll(userId){ return DB.notifications[userId]||[]; },
  markRead(userId){ if(DB.notifications[userId]) DB.notifications[userId]=DB.notifications[userId].map(n=>({...n,read:true})); },
};
const ModalBus = {
  _listeners: [],
  subscribe(fn){ this._listeners.push(fn); return ()=>{ this._listeners=this._listeners.filter(l=>l!==fn); }; },
  closeAll(except){ this._listeners.forEach(fn=>fn(except)); },
};
const calcAge = dob => {
  // Returns current age (how old they ARE today)
  const t=new Date(), b=new Date(dob);
  let a=t.getFullYear()-b.getFullYear();
  if(t.getMonth()-b.getMonth()<0||(t.getMonth()===b.getMonth()&&t.getDate()<b.getDate())) a--;
  return a;
};
const calcTurningAge = dob => {
  // Returns the age they are TURNING — always +1 from current unless today IS their birthday
  const t=new Date(), b=new Date(dob);
  const isToday = t.getMonth()===b.getMonth() && t.getDate()===b.getDate();
  return isToday ? calcAge(dob) : calcAge(dob) + 1;
};const isBirthday = dob => { const t=new Date(),b=new Date(dob); return t.getMonth()===b.getMonth()&&t.getDate()===b.getDate(); };
const daysUntil = dob => {
  const t=new Date(), b=new Date(dob);
  const next=new Date(t.getFullYear(),b.getMonth(),b.getDate());
  if(next<=t) next.setFullYear(t.getFullYear()+1);
  return Math.ceil((next-t)/(864e5));
};
const nextBirthdayMs = dob => {
  const t=new Date(), b=new Date(dob);
  const next=new Date(t.getFullYear(),b.getMonth(),b.getDate());
  if(next<=t) next.setFullYear(t.getFullYear()+1);
  return next.getTime()-t.getTime();
};
const nextBirthday = (dob) => { const t=new Date(),b=new Date(dob),n=new Date(t.getFullYear(),b.getMonth(),b.getDate()); if(n<=t)n.setFullYear(t.getFullYear()+1); return n; };
const fmt$ = n => `$${parseFloat(n).toFixed(2)}`;
const formatTs = (ts) => {
  if(!ts && ts!==0) return '';
  const d = new Date(typeof ts==='number'?ts:(ts instanceof Date?ts.getTime():0));
  if(isNaN(d.getTime())) return '';
  const now = Date.now();
  const diffMs = now - d.getTime();
  const diffMins = Math.floor(diffMs/60000);
  const diffHrs  = Math.floor(diffMs/3600000);
  const diffDays = Math.floor(diffMs/86400000);
  const timeStr  = d.toLocaleTimeString([],{hour:'numeric',minute:'2-digit'});
  if(diffMins < 1)  return 'Just now';
  if(diffMins < 60) return `${diffMins}m ago`;
  if(diffHrs < 24)  return `Today · ${timeStr}`;
  if(diffDays === 1) return `Yesterday · ${timeStr}`;
  if(diffDays < 7)  return `${d.toLocaleDateString([],{weekday:'short',month:'short',day:'numeric'})} · ${timeStr}`;
  return `${d.toLocaleDateString([],{month:'short',day:'numeric',year:'numeric'})} · ${timeStr}`;
};
const makeSlug = name => {
  const base = name.toLowerCase().replace(/\s+/g,"-").replace(/[^a-z0-9-]/g,"").slice(0,18);
  const suffix = Math.random().toString(36).slice(2,5);
  return `${base}-${suffix}`;
};
const makeUsernameBase = name => name.toLowerCase().replace(/\s+/g,"").replace(/[^a-z0-9]/g,"").slice(0,16);
const generateUsername = name => {
  const base = makeUsernameBase(name);
  if(!DB.users[base]) return base;
  let i = 2;
  while(DB.users[`${base}${i}`]) i++;
  return `${base}${i}`;
};
const isUsernameTaken = (username, excludeId='') => {
  return Object.values(DB.users).some(u => u.username===username && u.id!==excludeId);
};
const makeShortUrl = slug => `birthdayme.app/u/${slug}`;
const makeFullUrl  = slug => `https://birthdayme.app/u/${slug}`;
const QRCode = ({text, size=200, fg="#F0ECFF", bg="transparent"}) => {
  const canvasRef = useRef();
  useEffect(()=>{
    if(!canvasRef.current||!text) return;
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js";
    script.onload = () => {
      try {
        const canvas = canvasRef.current;
        if(!canvas) return;
        const parent = canvas.parentNode;
        const oldQR = parent.querySelector(".qr-wrapper");
        if(oldQR) oldQR.remove();
        const wrapper = document.createElement("div");
        wrapper.className = "qr-wrapper";
        wrapper.style.cssText = `width:${size}px;height:${size}px;border-radius:12px;overflow:hidden`;
        parent.insertBefore(wrapper, canvas);
        canvas.style.display = "none";
        new window.QRCode(wrapper, {
          text,
          width:size,
          height:size,
          colorDark:fg,
          colorLight:bg==="transparent"?"#16141C":bg,
          correctLevel:window.QRCode.CorrectLevel.M,
        });
      } catch(e){ console.warn("QR error",e); }
    };
    if(!window.QRCode) document.head.appendChild(script);
    else script.onload();
  },[text,size]);

  return (
    <div style={{display:"inline-block",position:"relative"}}>
      <canvas ref={canvasRef} style={{display:"none"}}/>
    </div>
  );
};
const QRPanel = ({slug, name}) => {
  const { t } = useTranslation();
  const url = makeFullUrl(slug);
  const [loaded, setLoaded] = useState(false);
  const wrapRef = useRef();

  const download = () => {
    const qrCanvas = wrapRef.current?.querySelector("canvas");
    if(!qrCanvas) return;
    const a = document.createElement("a");
    a.download = `${slug}-qr.png`;
    a.href = qrCanvas.toDataURL("image/png");
    a.click();
  };

  return (
    <div style={{textAlign:"center"}}>
      <div ref={wrapRef} style={{display:"inline-flex",flexDirection:"column",alignItems:"center",gap:12,padding:20,background:"var(--surface)",borderRadius:18,border:"1px solid var(--border)"}}>
        <div style={{padding:12,background:"var(--surface)",borderRadius:12,border:"1px solid var(--border)"}}>
          <QRCode text={url} size={160}/>
        </div>
        <div style={{fontSize:11,color:"var(--muted)",fontFamily:"monospace"}}>{makeShortUrl(slug)}</div>
        <div style={{fontSize:12,color:"var(--muted2)",lineHeight:1.5,maxWidth:220,textAlign:"center"}}>{t('common.scanToVisit')} {name}'s birthday link — contribute or join the app!</div>
      </div>
      <button onClick={download} style={{marginTop:12,width:"100%",padding:"11px",borderRadius:10,border:"1px solid var(--border)",background:"var(--s2)",color:"var(--muted2)",fontSize:13,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
        ⬇️ Save QR as Image
      </button>
    </div>
  );
};
const fmtCountdown = ms => {
  if(ms<=0) return {d:0,h:0,m:0,s:0};
  const s=Math.floor(ms/1000),mi=Math.floor(s/60),h=Math.floor(mi/60),d=Math.floor(h/24);
  return {d,h:h%24,m:mi%60,s:s%60};
};
async function askClaude(prompt) {
  const r = await fetch("https://api.anthropic.com/v1/messages",{
    method:"POST",headers:{"Content-Type":"application/json"},
    body:JSON.stringify({
      model:"claude-sonnet-4-20250514",max_tokens:800,
      system:"You are a warm, mystical astrology guide specializing in birthdays. Keep readings personal, vivid, positive, and concise — 3-4 sentences. Use 1-2 emojis naturally.",
      messages:[{role:"user",content:prompt}]
    })
  });
  const d=await r.json();
  return d.content?.[0]?.text||"The stars are quiet today…";
}
