const SocialLinksEditor = ({profile, onSave}) => {
  const [links, setLinks] = React.useState(profile.socialLinks||{});
  const [saved, setSaved] = React.useState(false);
  const set = (id,val) => setLinks(l=>({...l,[id]:val}));
  const save = () => { onSave({...profile, socialLinks:links}); setSaved(true); setTimeout(()=>setSaved(false),2000); };
  return (
    <div>
      {SOCIAL_PLATFORMS.map(p=>(
        <div key={p.id} style={{display:'flex',alignItems:'center',gap:10,marginBottom:10}}>
          <div style={{width:32,height:32,borderRadius:8,background:p.bg,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,boxShadow:`0 2px 6px ${typeof p.color==='string'&&p.color.startsWith('#')?p.color+'44':'rgba(0,0,0,.2)'}`}}>
          <span style={{display:'flex',alignItems:'center',justifyContent:'center',width:18,height:18,color:'#fff'}}>{p.svg}</span>
          </div>
          <div style={{flex:1,position:'relative'}}>
          <input value={links[p.id]||''} onChange={e=>set(p.id,e.target.value)} placeholder={p.placeholder}
          style={{width:'100%',fontSize:13,paddingLeft:8,borderColor:links[p.id]?p.color:'var(--border)',boxSizing:'border-box'}}/>
          </div>
          {links[p.id]&&<div style={{width:8,height:8,borderRadius:'50%',background:p.color,flexShrink:0}}/>}
        </div>
      ))}
      <button onClick={save} style={{width:'100%',padding:'11px',borderRadius:10,border:'none',background:'linear-gradient(135deg,var(--violet),var(--coral))',color:'#fff',fontWeight:800,fontSize:14,cursor:'pointer',fontFamily:"'Plus Jakarta Sans',sans-serif",marginTop:6}}>
        {saved?'✅ Saved!':'Save Social Links'}
      </button>
    </div>
  );
};

const SocialLinkBadges = ({profile}) => {
  const links = profile.socialLinks||{};
  const active = SOCIAL_PLATFORMS.filter(p=>links[p.id]);
  if(active.length===0) return null;
  return (
    <div style={{display:'flex',gap:8,flexWrap:'wrap',justifyContent:'center',marginTop:10,marginBottom:4}}>
      {active.map(p=>{
        const raw = links[p.id]||'';
        const url = raw.startsWith('http') ? raw : (p.prefix + raw.replace(/^@/,''));
        return (
          <a key={p.id} href={url} target="_blank" rel="noopener noreferrer"
          style={{display:'flex',alignItems:'center',gap:5,padding:'5px 12px',borderRadius:20,background:'var(--s2)',border:'1px solid var(--border)',textDecoration:'none',color:'var(--muted2)',fontSize:12,fontWeight:700,transition:'border-color .15s'}}
          onMouseEnter={e=>e.currentTarget.style.borderColor=p.color}
          onMouseLeave={e=>e.currentTarget.style.borderColor='var(--border)'}>
          <span style={{display:'flex',alignItems:'center',justifyContent:'center',width:14,height:14,color:p.color,flexShrink:0}}>{p.svg}</span>{p.label}
          </a>
        );
      })}
    </div>
  );
};
