    a=md5ii(a,b,c,d,wa[i],6,-198630844);d=md5ii(d,a,b,c,wa[i+7],10,1126891415);c=md5ii(c,d,a,b,wa[i+14],15,-1416354905);b=md5ii(b,c,d,a,wa[i+5],21,-57434055);
    a=md5ii(a,b,c,d,wa[i+12],6,1700485571);d=md5ii(d,a,b,c,wa[i+3],10,-1894986606);c=md5ii(c,d,a,b,wa[i+10],15,-1051523);b=md5ii(b,c,d,a,wa[i+1],21,-2054922799);
    a=md5ii(a,b,c,d,wa[i+8],6,1873313359);d=md5ii(d,a,b,c,wa[i+15],10,-30611744);c=md5ii(c,d,a,b,wa[i+6],15,-1560198380);b=md5ii(b,c,d,a,wa[i+13],21,1309151649);
    a=md5ii(a,b,c,d,wa[i+4],6,-145523070);d=md5ii(d,a,b,c,wa[i+11],10,-1120210379);c=md5ii(c,d,a,b,wa[i+2],15,718787259);b=md5ii(b,c,d,a,wa[i+9],21,-343485551);
