const POOL_FEE_RATE = 0.15; // 15% platform fee taken at contribution time
const calcPoolNet = (gross) => +(gross * (1 - POOL_FEE_RATE)).toFixed(2);
const calcPoolGross = (net) => +(net / (1 - POOL_FEE_RATE)).toFixed(2);

