// ── SmartGiftRecommendations — AI-powered gift suggestions ───────────────────
const SmartGiftRecommendations = ({senderId, recipientId, recipientProfile, onSelectStore}) => {
  const [recs, setRecs] = React.useState([]);
  const [loading, setLoading] = React.useState(false);
  const [aiRecs, setAiRecs] = React.useState(null);
  const [locationAsked, setLocationAsked] = React.useState(false);
  const [showLocation, setShowLocation] = React.useState(false);
  const context = React.useMemo(()=>GiftIntelligence.buildContext(senderId, recipientId),[senderId,recipientId]);
  const businesses = BusinessStore.getRanked(context, null, 8);

  React.useEffect(()=>{
    if(!context) return;
    // Instant rule-based
    setRecs(GiftIntelligence.getRuleBased(context));
    // Ask for location if not already asked this session
    if(!locationAsked && !GiftIntelligence._location) setShowLocation(true);
  },[context]);

  const loadAI = async () => {
    setLoading(true);
    const result = await GiftIntelligence.getAIRecommendations(context, businesses);
    if(result) setAiRecs(result);
    setLoading(false);
  };

  const handleLocationGrant = () => {
    GiftIntelligence.requestLocation(
      ({lat,lng})=>{ setShowLocation(false); setLocationAsked(true); },
      ()=>{ setShowLocation(false); setLocationAsked(true); }
    );
  };

  if(!context) return null;

  return (
    <div style={{marginBottom:16}}>
      {/* Location nudge */}
      {showLocation&&(
        <div style={{background:'rgba(6,214,160,.06)',border:'1px solid rgba(6,214,160,.2)',borderRadius:12,padding:'10px 14px',marginBottom:12,display:'flex',alignItems:'center',gap:10}}>
          <span style={{fontSize:20}}>📍</span>
          <div style={{flex:1}}>
            <div style={{fontSize:12,fontWeight:700,color:'var(--mint)'}}>Find local gift ideas</div>
            <div style={{fontSize:11,color:'var(--muted)'}}>Share location to see nearby businesses</div>
          </div>
          <button onClick={handleLocationGrant}
            style={{padding:'5px 12px',borderRadius:8,border:'none',background:'var(--mint)',color:'var(--bg)',fontSize:11,fontWeight:700,cursor:'pointer',flexShrink:0}}>
            Allow
          </button>
          <button onClick={()=>{setShowLocation(false);setLocationAsked(true);}}
            style={{background:'none',border:'none',color:'var(--muted)',fontSize:18,cursor:'pointer',lineHeight:1}}>×</button>
        </div>
      )}

      {/* Rule-based quick suggestions */}
      {recs.length>0&&(
        <div style={{marginBottom:14}}>
          <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8,display:'flex',alignItems:'center',gap:6}}>
            💡 Gift ideas for {context.recipient.name}
          </div>
          <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
            {recs.map((r,i)=>(
              <div key={i} style={{
                padding:'5px 11px',borderRadius:20,fontSize:12,fontWeight:600,cursor:'default',
                background:'rgba(155,93,229,.08)',border:'1px solid rgba(155,93,229,.2)',
                color:'var(--violet2)',
              }}>{r}</div>
            ))}
          </div>
        </div>
      )}

      {/* Featured businesses */}
      {businesses.length>0&&(
        <div style={{marginBottom:14}}>
          <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8}}>
            🏪 Shop for {context.recipient.name}
          </div>
          <div style={{display:'flex',gap:8,overflowX:'auto',paddingBottom:4,scrollbarWidth:'none'}}>
            {businesses.map(biz=>(
              <div key={biz.id}
                onClick={()=>{ BusinessStore.recordClick(biz.id); onSelectStore?.(biz); window.open(biz.giftCardUrl||biz.website,'_blank','noopener'); }}
                style={{flexShrink:0,width:110,background:'var(--surface)',borderRadius:12,padding:'10px 10px 8px',border:'1px solid var(--border)',cursor:'pointer',transition:'all .15s',textAlign:'center'}}
                onMouseEnter={e=>{e.currentTarget.style.borderColor='var(--gold)';e.currentTarget.style.transform='translateY(-2px)';}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor='var(--border)';e.currentTarget.style.transform='none';}}>
                {/* Logo */}
                <div style={{width:40,height:40,margin:'0 auto 6px',borderRadius:10,background:'var(--s2)',overflow:'hidden',display:'flex',alignItems:'center',justifyContent:'center'}}>
                  <img
                    src={biz.logoUrl||`https://img.logo.dev/${biz.domain}?token=${import.meta.env.VITE_LOGO_DEV_TOKEN||''}&size=80`}
                    style={{width:'100%',height:'100%',objectFit:'contain'}}
                    alt={biz.name}
                    onError={e=>{e.target.style.display='none';e.target.nextSibling.style.display='flex';}}
                  />
                  <div style={{display:'none',width:'100%',height:'100%',alignItems:'center',justifyContent:'center',fontSize:18}}>🏪</div>
                </div>
                <div style={{fontSize:11,fontWeight:700,color:'var(--text)',marginBottom:3,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{biz.name}</div>
                {/* Badges */}
                {biz.badges.slice(0,1).map(bid=>{
                  const badge = BUSINESS_BADGES.find(b=>b.id===bid);
                  const isOfficial = bid==='birthdayme_official';
                  return badge?(<div key={bid} style={{fontSize:9,fontWeight:700,color:isOfficial?'var(--violet2)':badge.color,marginBottom:2,display:'flex',alignItems:'center',gap:3}}>
                    {isOfficial&&<i className="fas fa-certificate" style={{fontSize:8}}/>}
                    {badge.icon} {badge.label}
                  </div>):null;
                })}
                {biz.tier==='premium'&&!biz.badges.includes('premium')&&(
                  <div style={{fontSize:9,color:'var(--gold)',fontWeight:600}}>⭐ Featured</div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* AI enhance button */}
      {!aiRecs&&(
        <button onClick={loadAI} disabled={loading}
          style={{
            width:'100%',padding:'10px',borderRadius:12,border:'1px solid rgba(155,93,229,.25)',
            background:'rgba(155,93,229,.06)',color:'var(--violet2)',
            fontSize:12,fontWeight:700,cursor:loading?'wait':'pointer',
            display:'flex',alignItems:'center',justifyContent:'center',gap:7,
          }}>
          {loading
            ? <><span style={{animation:'spin 1s linear infinite',display:'inline-block'}}>⚡</span> Personalizing…</>
            : '✨ Get AI-personalized suggestions for ' + context.recipient.name}
        </button>
      )}

      {/* AI recommendations */}
      {aiRecs&&(
        <div>
          <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8,display:'flex',alignItems:'center',gap:6}}>
            ✨ Personalized for {context.recipient.name}
          </div>
          <div style={{display:'flex',flexDirection:'column',gap:8}}>
            {aiRecs.map((r,i)=>(
              <div key={i} style={{background:'var(--surface)',borderRadius:12,padding:'11px 13px',border:'1px solid var(--border)',display:'flex',alignItems:'flex-start',gap:10}}>
                <div style={{fontSize:18,flexShrink:0,marginTop:1}}>🎁</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:700,fontSize:13,color:'var(--text)',marginBottom:2}}>{r.title}</div>
                  <div style={{fontSize:11,color:'var(--muted)',lineHeight:1.5}}>{r.reason}</div>
                  <div style={{display:'flex',gap:6,marginTop:5,flexWrap:'wrap'}}>
                    <span style={{fontSize:10,fontWeight:700,color:'var(--mint)',background:'rgba(6,214,160,.1)',padding:'2px 7px',borderRadius:20}}>{r.priceRange}</span>
                    {r.storeHint&&<span style={{fontSize:10,color:'var(--muted)',background:'var(--s2)',padding:'2px 7px',borderRadius:20,fontWeight:600}}>{r.storeHint}</span>}
                    {r.urgency==='high'&&<span style={{fontSize:10,fontWeight:700,color:'var(--coral)',background:'rgba(255,94,91,.1)',padding:'2px 7px',borderRadius:20}}>⚡ Act soon</span>}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const CardSigningStore = {
  // signatures: { cardId: [{userId, displayName, message, emoji, fontId, ts, isAnonymous}] }
  sign(cardId, userId, displayName, message, emoji='🎂', fontId='caveat', isAnonymous=false) {
    if(!DB.cardSignatures) DB.cardSignatures = {};
    if(!DB.cardSignatures[cardId]) DB.cardSignatures[cardId] = [];
    const existing = DB.cardSignatures[cardId].findIndex(s=>s.userId===userId);
    const sig = {userId, displayName: isAnonymous?'A secret admirer':displayName, message, emoji, fontId, ts:Date.now(), isAnonymous};
    if(existing>-1) DB.cardSignatures[cardId][existing] = sig;
    else DB.cardSignatures[cardId].push(sig);
    return sig;
  },
  getSignatures(cardId) { return (DB.cardSignatures||{})[cardId]||[]; },
  hasSigned(cardId, userId) { return this.getSignatures(cardId).some(s=>s.userId===userId); },
  remove(cardId, userId) {
    if(!DB.cardSignatures?.[cardId]) return;
    DB.cardSignatures[cardId] = DB.cardSignatures[cardId].filter(s=>s.userId!==userId);
  },
};


