              {sw.eligibility?.genders?.length>0&&<span style={{fontSize:10,fontWeight:700,padding:'3px 9px',borderRadius:20,background:'rgba(255,138,216,.1)',color:'#FF8AD8',border:'1px solid rgba(255,138,216,.2)'}}>👤 {sw.eligibility.genders.join(' / ')}</span>}
              {sw.eligibility?.tiers?.length>0&&<span style={{fontSize:10,fontWeight:700,padding:'3px 9px',borderRadius:20,background:'rgba(155,93,229,.1)',color:'var(--violet2)',border:'1px solid rgba(155,93,229,.2)'}}>⭐ {sw.eligibility.tiers.join(' / ')}</span>}
